const items = $input.all();

  if (items.length === 1 && (items[0].json.noResults || items[0].json.noNewGrants)) {
    return items;
  }

  function extractDate(grant) {
    const candidates = [
      grant.closeDate,
      grant.deadline,
      grant.dueDate,
      grant.due_date,
      grant.endDate,
      grant.end_date,
      grant.applicationDeadline,
      grant.application_deadline,
    ];

    for (const val of candidates) {
      if (!val || typeof val !== 'string') continue;
      const parsed = new Date(val);
      if (!isNaN(parsed.getTime()) && parsed.getFullYear() > 2000) {
        return parsed;
      }
    }

    if (grant.description) {
      const match = grant.description.match(/(\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4})|(\w+ \d{1,2},? \d{4})/);
      if (match) {
        const parsed = new Date(match[0]);
        if (!isNaN(parsed.getTime()) && parsed.getFullYear() > 2000) {
          return parsed;
        }
      }
    }

    return null;
  }

  const withDeadline = [];
  const noDeadline = [];

  for (const item of items) {
    const date = extractDate(item.json);
    if (date) {
      item._sortDate = date;
      withDeadline.push(item);
    } else {
      noDeadline.push(item);
    }
  }

  withDeadline.sort((a, b) => a._sortDate - b._sortDate);

  const combined = [...withDeadline, ...noDeadline];
  return combined.map(item => ({ json: item.json }));

// ============================================================
  // Filter, Insert & Screen Grants (Internal Loop)
  // ============================================================
  // Replaces Loop Over Items3, Check Already Tracked, Has New Grants,
  // Log Raw Source Counts, and 11 downstream nodes.
  // n8n's Split In Batches node loses items when the data shape
  // changes between iterations (AI response vs grant objects).
  // This node loops internally in JS for reliable processing.
  // ============================================================

  const BATCH_SIZE = 40;
  const DEDUP_BATCH = 200;
  const items = $input.all();

  // Get webhook data
  let orgId, callbackUrl;
  try {
    const webhookData = $('Fetch Grants Webhook').first().json.body;
    orgId = webhookData?.org_id;
    callbackUrl = webhookData?.callback_url;
  } catch(e) {}

  if (!orgId) {
    return [{ json: { error: true, message: 'No org_id provided' } }];
  }

  const openAiKey = 'REPLACE_ME';

  const supabaseUrl = 'https://fgudhlcktsstwpxwtwzz.supabase.co/rest/v1';
  const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZndWRobGNrdHNzdHdweHd0d3p6Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDk2NjA5NSwiZXhwIjoyMDg2NTQyMDk1fQ.lDXOCM7CStNfF0G-ZENg5x1dyQ0ytXHGtJ8DjQNd03I';
  const supaHeaders = {
    'apikey': supabaseKey,
    'Authorization': 'Bearer ' + supabaseKey,
    'Content-Type': 'application/json',
  };
  const supaReadHeaders = {
    'apikey': supabaseKey,
    'Authorization': 'Bearer ' + supabaseKey,
  };
  const webhookHeaders = {
    'Content-Type': 'application/json',
    'x-webhook-secret': 't+KHcyHWsievwSbCyHvDJk5/YbZayMsiKp0letIw0Xk='
  };

  // Helper: send status callback
  async function sendStatus(status, stage_message) {
    if (!callbackUrl || !orgId) return;
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: callbackUrl,
        headers: webhookHeaders,
        body: { org_id: orgId, status, stage_message }
      });
    } catch(e) {}
  }

  // --- STEP 1: Batched Dedup Check ---
  await sendStatus.call(this, 'checking', 'Checking for duplicates in your pipeline...');

  const allItems = items.map(i => i.json);
  const oppNums = allItems
    .map(g => (g.oppNum || '').trim())
    .filter(id => id.length > 0);

  const existingOppNums = new Set();

  for (let i = 0; i < oppNums.length; i += DEDUP_BATCH) {
    const chunk = oppNums.slice(i, i + DEDUP_BATCH);
    const filter = chunk.map(id => '"' + id.replace(/"/g, '') + '"').join(',');

    await sendStatus.call(this, 'checking', 'Checking duplicates — ' + Math.min(i + DEDUP_BATCH, oppNums.length) + ' of ' + oppNums.length + ' grants...');

    try {
      const response = await this.helpers.httpRequest({
        method: 'GET',
        url: supabaseUrl + '/grants?source_id=in.(' + filter + ')&org_id=eq.' + orgId + '&select=source_id',
        headers: supaReadHeaders,
      });
      if (Array.isArray(response)) {
        for (const r of response) {
          existingOppNums.add((r.source_id || '').trim());
        }
      }
    } catch(e) {}
  }

  // Filter to new grants only
  const newGrants = [];
  for (const grant of allItems) {
    const oppNum = (grant.oppNum || '').trim();
    if (!oppNum || existingOppNums.has(oppNum)) continue;
    newGrants.push(grant);
  }

  // --- STEP 2: If no new grants, mark complete and exit ---
  if (newGrants.length === 0) {
    await sendStatus.call(this, 'complete', 'Grant search complete!');
    return [{ json: { success: true, message: 'All grants already tracked', totalInserted: 0 } }];
  }

  // --- STEP 3: Log source counts ---
  const sourceCounts = {};
  for (const grant of newGrants) {
    const source = grant.source || 'Unknown';
    sourceCounts[source] = (sourceCounts[source] || 0) + 1;
  }

  const today = new Date().toISOString().split('T')[0];
  try {
    await this.helpers.httpRequest({
      method: 'DELETE',
      url: supabaseUrl + '/grant_source_stats?org_id=eq.' + orgId + '&fetch_date=eq.' + today,
      headers: supaHeaders,
    });

    const rows = Object.entries(sourceCounts).map(([source, raw_count]) => ({
      org_id: orgId, source, raw_count, fetch_date: today
    }));

    await this.helpers.httpRequest({
      method: 'POST',
      url: supabaseUrl + '/grant_source_stats',
      headers: supaHeaders,
      body: JSON.stringify(rows),
    });
  } catch(e) {}

  // --- STEP 4: Fetch org data (once) ---
  const orgs = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/organizations?id=eq.' + encodeURIComponent(orgId) + '&select=id,geographic_focus,address',
    headers: supaReadHeaders,
  });

  if (!Array.isArray(orgs) || orgs.length === 0) {
    return [{ json: { error: true, message: 'Organization not found: ' + orgId } }];
  }
  const org = orgs[0];

  // Fetch org narratives (once)
  const narratives = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/documents?org_id=eq.' + encodeURIComponent(orgId) + '&select=title,extracted_text,category&order=updated_at.desc&limit=10',
    headers: supaReadHeaders,
  });

  let nicheSummary = '';
  if (Array.isArray(narratives) && narratives.length > 0) {
    nicheSummary = narratives.map(n => {
      return (n.title || n.category || '') + ': ' + (n.extracted_text || '');
    }).join('\n\n');
  }

  // Build grants list for AI processing
  const allGrantsForAI = newGrants.map(grant => ({
    title: grant.title || '',
    agency: grant.agency || null,
    agencyCode: grant.agencyCode || '',
    description: grant.description || '',
    awardFloor: grant.awardFloor || 0,
    awardCeiling: grant.awardCeiling || 0,
    openDate: grant.openDate || '',
    closeDate: grant.closeDate || '',
    status: grant.status || '',
    source: grant.source || 'Grant Scanner',
    source_id: grant.oppNum || grant.source_id,
    source_url: grant.link || grant.source_url,
  }));

  // --- STEP 5: Process in AI batches ---
  const totalBatches = Math.ceil(allGrantsForAI.length / BATCH_SIZE);
  let totalInserted = 0;
  let totalScreened = 0;

  const systemPrompt = `You are a grant eligibility and classification assistant. Given a grant, an organization with its location, and the organization's
  narratives (which describe its mission, programs, and focus areas), first classify the grant type, then determine if the organization is eligible by
  location, then evaluate niche alignment.

  STEP 1 - CLASSIFY THE GRANT TYPE:
  - Federal: Funded by federal agencies (HHS, SAMHSA, ACF, DOL, ED, HUD, USDA, etc.) or listed on Grants.gov. grant_state = null.
   - State grants: The organization is ONLY eligible if it operates in, is headquartered in, or serves communities in the grant's state.
      1. Identify the grant's state by reading the full grant details - look at the funding agency, program description, and any geographic restrictions.
      2. Check the organization's geographic_focus and address fields.
      3. The org is eligible if ANY of the following match the grant's state:
         - The org's address/headquarters is in that state
         - The org's geographic_focus includes that state or regions/counties within it
         - The org explicitly states it serves that state's communities
      4. Matching rules: Accept abbreviations (PA = Pennsylvania, NJ = New Jersey), typos, partial matches, and county/city-level references within the
  state.
      5. The org is NOT eligible if its geographic_focus and address clearly indicate a different state with no overlap.
      6. If the org has no location data at all, mark eligible and note that location could not be verified.
  - Philanthropic: From private foundations, trusts, corporate giving programs, or nonprofits (e.g. Gates Foundation, Ford Foundation). grant_state = null.

  STEP 2 - DETERMINE LOCATION ELIGIBILITY:
  - Federal grants: The organization IS eligible.
  - Philanthropic grants: The organization IS eligible.
  - State grants: The organization is ONLY eligible if it is located in or serves that state. Check geographic_focus and address. Be flexible with matching
  - abbreviations (NJ = New Jersey), typos, and partial matches count. If the org has no location data, give benefit of the doubt and mark eligible.

  STEP 3 - EVALUATE NICHE ALIGNMENT (STRICT):
  Use the organization's narratives to understand what the org actually does — its mission, programs, populations served, and sector/industry focus. Compare against the grant's purpose and description.

  - Mark niche_aligned = true ONLY if the grant directly funds work in one of the org's stated program areas, populations, or sectors. There must be a concrete, specific overlap between what the grant funds and what the org actually does.
  - A shared broad theme alone (e.g., "community", "wellbeing", "equity", "capacity building") is NOT sufficient. The grant's focus area must map to a program or population the org explicitly describes working on.
  - Mark niche_aligned = false if the grant targets a different sector, population, or program area than the org's narratives describe — even if there is a tangential or metaphorical connection.
  - Mark niche_aligned = false if alignment would require more than one logical hop (e.g., "the org serves youth, and youth live in communities, and this grant funds communities").
  - When in doubt, mark niche_aligned = false. Prefer fewer, highly-aligned grants over many loosely-related ones.
  - If no narratives are available, mark niche_aligned = false (cannot verify alignment — do not give benefit of the doubt).

  The grant must pass BOTH location eligibility AND niche alignment to be marked eligible. Any grant outside the org's clear niche must be rejected.

  Return ONLY valid JSON — an array with one object per grant in the same order, each with:
  {
    "grant_type": "federal" or "state" or "philanthropic",
    "grant_state": "Full state name if state grant, otherwise null",
    "location_eligible": true or false,
    "niche_aligned": true or false,
    "eligible": true or false,
    "reason": "brief explanation"
  }`;

  for (let b = 0; b < totalBatches; b++) {
    const start = b * BATCH_SIZE;
    const batch = allGrantsForAI.slice(start, start + BATCH_SIZE);

    // Status: Matching
    await sendStatus.call(this, 'filtering', 'Matching grants to your organization... (' + (start + batch.length) + ' of ' + allGrantsForAI.length + ')');

    // Build AI prompt
    const userPrompt = `
    Organization:
    - ID: ${org.id}
    - Location: ${org.geographic_focus ? (Array.isArray(org.geographic_focus) ? org.geographic_focus.join(', ') : org.geographic_focus) : 'Not set'}
    - Address: ${org.address || 'Not set'}

    Organization Narratives (niche/focus context):
    ${nicheSummary || 'No narratives available'}

    Evaluate EACH grant below against the organization above. For each grant, classify its type, determine location eligibility, and evaluate niche
  alignment per your instructions.

    Grants:
    ${JSON.stringify(batch, null, 2)}`;

    // Call OpenAI
    let parsedResults = [];
    try {
      const aiResponse = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://api.openai.com/v1/chat/completions',
        headers: {
          'Authorization': 'Bearer ' + openAiKey,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          model: 'gpt-4.1-mini',
          messages: [
            { role: 'system', content: systemPrompt },
            { role: 'user', content: userPrompt }
          ],
          temperature: 0,
        }),
      });

      const aiText = aiResponse.choices?.[0]?.message?.content || '[]';
      const cleaned = aiText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
      const parsed = JSON.parse(cleaned);
      parsedResults = Array.isArray(parsed) ? parsed : [parsed];
    } catch(e) {
      parsedResults = batch.map(() => ({
        grant_type: 'federal', grant_state: null,
        location_eligible: true, niche_aligned: true,
        eligible: true, reason: 'AI parse failed, defaulting to eligible'
      }));
    }

    // Build insert payloads for eligible grants
    const toInsert = [];
    batch.forEach((grant, index) => {
      const parsed = parsedResults[index] || parsedResults[0] || {
        grant_type: 'federal', grant_state: null,
        location_eligible: true, niche_aligned: true,
        eligible: true, reason: 'No AI result for this grant'
      };

      if (parsed.eligible === false) return;

      const description = grant.description || '';
      const descriptionHtml = '<div><h3>Grant Opportunity</h3>' +
        '<p><strong>Source:</strong> ' + (grant.source || '') + '</p>' +
        '<p><strong>Agency:</strong> ' + (grant.agency || '') + '</p>' +
        '<p><strong>Type:</strong> ' + (parsed.grant_type || 'unknown') + '</p>' +
        (parsed.grant_state ? '<p><strong>State:</strong> ' + parsed.grant_state + '</p>' : '') +
        '<p><strong>Award Range:</strong> $' + (grant.awardFloor || 0) + ' - $' + (grant.awardCeiling || 0) + '</p>' +
        '<p><strong>Open Date:</strong> ' + (grant.openDate || '') + '</p>' +
        '<p><strong>Deadline:</strong> ' + (grant.closeDate || '') + '</p>' +
        '<hr><h4>Description:</h4>' +
        '<p>' + description + '</p>' +
        '<p><em>Location Filter: ' + (parsed.reason || 'N/A') + '</em></p>' +
        '<hr>' +
        '<p><a href="' + (grant.source_url || grant.link || '') + '">View Original Listing</a></p>' +
        '</div>';

      let deadlineValue = null;
      if (grant.closeDate && grant.closeDate !== 'See listing' && grant.closeDate !== 'Not specified' && grant.closeDate !== 'Rolling') {
        const d = new Date(grant.closeDate);
        if (!isNaN(d.getTime())) {
          const yyyy = d.getUTCFullYear();
          const mm = String(d.getUTCMonth() + 1).padStart(2, '0');
          const dd = String(d.getUTCDate()).padStart(2, '0');
          deadlineValue = yyyy + '-' + mm + '-' + dd + 'T00:00:00.000Z';
        } else {
          deadlineValue = grant.closeDate;
        }
      }

      toInsert.push({
        org_id: org.id,
        title: grant.title || '',
        funder_name: grant.agency || null,
        description: description,
        amount: grant.awardCeiling > 0 ? grant.awardCeiling : null,
        deadline: deadlineValue,
        stage: 'discovery',
        source: grant.source || 'Grant Scanner',
        source_id: grant.source_id || grant.oppNum,
        source_url: grant.source_url || grant.link,
        metadata: {
          grants_gov_id: grant.id,
          agency_code: grant.agencyCode,
          open_date: grant.openDate,
          award_floor: grant.awardFloor,
          award_ceiling: grant.awardCeiling,
          grant_type: parsed.grant_type || 'unknown',
          grant_state: parsed.grant_state || null,
          location_filter_reason: parsed.reason || '',
          location_eligible: parsed.location_eligible !== false,
          niche_aligned: parsed.niche_aligned !== false,
          priority: 'medium',
          description_html: descriptionHtml
        }
      });
    });

    // Insert eligible grants to Supabase
    if (toInsert.length > 0) {
      await sendStatus.call(this, 'inserting', 'Adding matched grants to your pipeline... (' + (start + batch.length) + ' of ' + allGrantsForAI.length +
  ')');

      await Promise.all(toInsert.map(async (grant) => {
        try {
          const insertedRows = await this.helpers.httpRequest({
            method: 'POST',
            url: supabaseUrl + '/grants?on_conflict=org_id,source_id',
            headers: {
              ...supaHeaders,
              'Prefer': 'return=representation,resolution=ignore-duplicates',
            },
            body: JSON.stringify(grant),
          });
          if (Array.isArray(insertedRows) && insertedRows.length > 0) {
            grant._dbId = insertedRows[0].id;
          }
          totalInserted++;
        } catch(e) {}
      }));
    }

    // Fire-and-forget eligibility screener (awaiting here was hitting the 300s runner timeout).
    for (const grant of toInsert) {
      if (!grant._dbId) continue;
      this.helpers.httpRequest({
        method: 'POST',
        url: 'https://n8n.thebrownmine.com/webhook/screen-grant',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          url: grant.source_url || '',
          grantid: grant._dbId,
          orgId: grant.org_id || '',
          grantData: {
            title: grant.title || '',
            agency: grant.funder_name || '',
            awardRange: grant.amount ? String(grant.amount) : 'Not specified',
            deadline: grant.deadline || '',
            description: grant.description || '',
            source: grant.source || '',
            org_id: grant.org_id || ''
          }
        }),
        timeout: 5000,
      }).catch(() => {});
      totalScreened++;
    }
  }

  // --- STEP 6: Status Complete ---
  await sendStatus.call(this, 'complete', 'Grant search complete!');

  return [{ json: { success: true, totalInserted, totalScreened, totalGrants: allGrantsForAI.length, batches: totalBatches } }];

// Status callback helper: only sends status if callback_url exists (new org registration)
// This node is placed at different stages of the pipeline
const items = $input.all();

// Try to get webhook data
let callbackUrl, orgId, webhookSecret;
try {
  const webhookData = $('Fetch Grants Webhook').first().json.body;
  callbackUrl = webhookData?.callback_url;
  orgId = webhookData?.org_id;
  webhookSecret = webhookData?.is_new_org;
} catch(e) {
  // Not triggered via webhook (scheduled run) - skip status updates
  return items;
}

if (!callbackUrl || !orgId) return items;

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: callbackUrl,
    headers: {
      'Content-Type': 'application/json',
      'x-webhook-secret': 't+KHcyHWsievwSbCyHvDJk5/YbZayMsiKp0letIw0Xk='
    },
    body: {
      org_id: orgId,
      status: 'searching',
      stage_message: 'Searching Grants.gov and federal databases...'
    }
  });
} catch(e) {
  // Don't fail the workflow if status update fails
}

return items;

// ============================================================
// Fetch Central Grants
// Pulls from the central_grants catalog instead of scraping
// external sources. The daily ingest workflow keeps the catalog
// fresh; this node just reads from it and hands rows downstream
// to Combine & Deduplicate → Filter Insert & Screen Grants.
// ============================================================

const supabaseUrl = 'https://fgudhlcktsstwpxwtwzz.supabase.co/rest/v1';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZndWRobGNrdHNzdHdweHd0d3p6Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDk2NjA5NSwiZXhwIjoyMDg2NTQyMDk1fQ.lDXOCM7CStNfF0G-ZENg5x1dyQ0ytXHGtJ8DjQNd03I';

const selectCols = 'id,title,funder_name,organization,description,source,source_id,source_url,deadline,amount,eligibility,categories,metadata,last_seen_at';
const url = supabaseUrl + '/central_grants?select=' + selectCols + '&limit=2000&order=last_seen_at.desc';

let rows = [];
try {
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url: url,
    headers: {
      'apikey': supabaseKey,
      'Authorization': 'Bearer ' + supabaseKey,
    },
  });
  if (Array.isArray(res)) rows = res;
} catch (e) {}

// Drop expired grants. Null deadline = rolling/open-ended → keep.
const todayIso = new Date().toISOString().slice(0, 10);
const live = rows.filter(r => !r.deadline || r.deadline >= todayIso);

// Shape each row for downstream nodes. Filter Insert & Screen Grants
// keys off `oppNum` for dedup, so alias source_id → oppNum.
return live.map(r => ({
  json: {
    id: r.id,
    oppNum: r.source_id || r.id,
    title: r.title || '',
    description: r.description || '',
    agency: r.funder_name || '',
    funder_name: r.funder_name || '',
    organization: r.organization || '',
    source: r.source || '',
    source_id: r.source_id || null,
    source_url: r.source_url || null,
    link: r.source_url || null,
    deadline: r.deadline || null,
    closeDate: r.deadline || null,
    amount: r.amount || null,
    eligibility: r.eligibility || null,
    categories: r.categories || null,
    metadata: r.metadata || null,
  },
}));
